ਸੂਚਨਾ: ਹੇਠਾਂ ਦਿੱਤਾ ਕੋਡ ਦਿਖਾਉਂਦਾ ਹੈ ਕਿ libarchive ਲਾਇਬ੍ਰੇਰੀ ਨਾਲ tar ਫਾਈਲ ਦੀ ਸਮੱਗਰੀ ਨੂੰ ਦਿੱਤੇ ਗਏ ਮੰਜ਼ਿਲ ਪੱਥਰ 'ਤੇ ਕਿਵੇਂ ਕੱਢਣਾ ਹੈ।

@param tar_path: tar ਫਾਈਲ ਦਾ ਪੱਥਰ
@param dest_path: ਮੰਜ਼ਿਲ ਫੋਲਡਰ ਦਾ ਪੱਥਰ

@return ਜੇਕਰ ਕੱਢਣਾ ਸਫਲ ਹੈ ਤਾਂ ਸੱਚਾ; ਨਹੀਂ ਤਾਂ, ਝੂਠਾ */// ਆਰਕਾਈਵ ਲੇਖਕ ਨੂੰ ਸ਼ੁਰੂ ਕਰੋ    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// ਹਰ ਐਂਟਰੀ ਨੂੰ ਪੜ੍ਹੋ ਅਤੇ ਕੱਢੋ    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // ਪੂਰਾ ਪੱਥਰ ਬਣਾਓ        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// ਹੈਡਰ ਲਿਖੋ        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// ਡਾਟਾ ਕਾਪੀ ਕਰੋ        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


